-- Initial ChapterOne Books schema. Run with: npx prisma migrate deploy
CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TYPE "UserRole" AS ENUM ('CUSTOMER', 'ADMIN');
CREATE TYPE "BookFormat" AS ENUM ('PHYSICAL', 'DIGITAL');
CREATE TYPE "OrderStatus" AS ENUM ('PENDING', 'PAID', 'PROCESSING', 'SHIPPED', 'DELIVERED', 'CANCELLED');
CREATE TYPE "PaymentStatus" AS ENUM ('UNPAID', 'PAID', 'REFUNDED', 'FAILED');
CREATE TABLE "User" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "supabaseUserId" TEXT NOT NULL UNIQUE, "email" TEXT NOT NULL UNIQUE, "name" TEXT, "role" "UserRole" NOT NULL DEFAULT 'CUSTOMER', "avatarUrl" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Author" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "name" TEXT NOT NULL, "slug" TEXT NOT NULL UNIQUE, "bio" TEXT, "imageUrl" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Category" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "name" TEXT NOT NULL UNIQUE, "slug" TEXT NOT NULL UNIQUE, "description" TEXT);
CREATE TABLE "Book" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "slug" TEXT NOT NULL UNIQUE, "title" TEXT NOT NULL, "isbn" TEXT NOT NULL UNIQUE, "description" TEXT NOT NULL, "publisher" TEXT NOT NULL, "publishedAt" TIMESTAMP(3) NOT NULL, "language" TEXT NOT NULL DEFAULT 'English', "pages" INTEGER NOT NULL, "format" "BookFormat" NOT NULL DEFAULT 'PHYSICAL', "priceCents" INTEGER NOT NULL, "salePriceCents" INTEGER, "coverUrl" TEXT NOT NULL, "previewImages" TEXT[] NOT NULL, "sampleUrl" TEXT, "rating" DECIMAL(2,1) NOT NULL DEFAULT 0, "reviewCount" INTEGER NOT NULL DEFAULT 0, "isFeatured" BOOLEAN NOT NULL DEFAULT false, "isStaffPick" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "authorId" TEXT NOT NULL);
CREATE TABLE "BookCategory" ("bookId" TEXT NOT NULL, "categoryId" TEXT NOT NULL, PRIMARY KEY ("bookId", "categoryId"));
CREATE TABLE "Inventory" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "bookId" TEXT NOT NULL UNIQUE, "quantity" INTEGER NOT NULL DEFAULT 0, "reorderAt" INTEGER NOT NULL DEFAULT 5, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Order" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "orderNumber" TEXT NOT NULL UNIQUE, "userId" TEXT, "email" TEXT NOT NULL, "status" "OrderStatus" NOT NULL DEFAULT 'PENDING', "paymentStatus" "PaymentStatus" NOT NULL DEFAULT 'UNPAID', "stripeSessionId" TEXT UNIQUE, "subtotalCents" INTEGER NOT NULL, "shippingCents" INTEGER NOT NULL, "taxCents" INTEGER NOT NULL, "totalCents" INTEGER NOT NULL, "shippingAddress" JSONB, "billingAddress" JSONB, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "OrderItem" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "orderId" TEXT NOT NULL, "bookId" TEXT NOT NULL, "title" TEXT NOT NULL, "unitCents" INTEGER NOT NULL, "quantity" INTEGER NOT NULL);
CREATE TABLE "Review" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "userId" TEXT NOT NULL, "bookId" TEXT NOT NULL, "rating" INTEGER NOT NULL, "title" TEXT, "body" TEXT NOT NULL, "approved" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("userId", "bookId"));
CREATE TABLE "WishlistItem" ("userId" TEXT NOT NULL, "bookId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY("userId", "bookId"));
CREATE TABLE "Address" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "userId" TEXT NOT NULL, "label" TEXT NOT NULL, "firstName" TEXT NOT NULL, "lastName" TEXT NOT NULL, "line1" TEXT NOT NULL, "line2" TEXT, "city" TEXT NOT NULL, "province" TEXT NOT NULL, "postalCode" TEXT NOT NULL, "country" TEXT NOT NULL DEFAULT 'South Africa', "isDefault" BOOLEAN NOT NULL DEFAULT false);
CREATE TABLE "RecentlyViewed" ("userId" TEXT NOT NULL, "bookId" TEXT NOT NULL, "viewedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY("userId", "bookId"));
CREATE TABLE "Coupon" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "code" TEXT NOT NULL UNIQUE, "percentOff" INTEGER, "amountOffCents" INTEGER, "usageLimit" INTEGER, "usedCount" INTEGER NOT NULL DEFAULT 0, "expiresAt" TIMESTAMP(3), "active" BOOLEAN NOT NULL DEFAULT true);
CREATE TABLE "BlogPost" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "slug" TEXT NOT NULL UNIQUE, "title" TEXT NOT NULL, "excerpt" TEXT NOT NULL, "body" TEXT NOT NULL, "coverUrl" TEXT, "publishedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "NewsletterSubscriber" ("id" TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text, "email" TEXT NOT NULL UNIQUE, "subscribedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "confirmedAt" TIMESTAMP(3), "source" TEXT);
CREATE TABLE "RelatedBook" ("bookId" TEXT NOT NULL, "relatedBookId" TEXT NOT NULL, PRIMARY KEY("bookId", "relatedBookId"));
CREATE INDEX "Book_title_idx" ON "Book"("title"); CREATE INDEX "Book_authorId_idx" ON "Book"("authorId"); CREATE INDEX "Book_publishedAt_idx" ON "Book"("publishedAt"); CREATE INDEX "Book_priceCents_idx" ON "Book"("priceCents"); CREATE INDEX "Inventory_quantity_idx" ON "Inventory"("quantity"); CREATE INDEX "Order_userId_createdAt_idx" ON "Order"("userId", "createdAt"); CREATE INDEX "Order_status_idx" ON "Order"("status"); CREATE INDEX "Review_bookId_approved_idx" ON "Review"("bookId", "approved"); CREATE INDEX "Address_userId_idx" ON "Address"("userId"); CREATE INDEX "RecentlyViewed_userId_viewedAt_idx" ON "RecentlyViewed"("userId", "viewedAt"); CREATE INDEX "BlogPost_publishedAt_idx" ON "BlogPost"("publishedAt");
ALTER TABLE "Book" ADD CONSTRAINT "Book_authorId_fkey" FOREIGN KEY ("authorId") REFERENCES "Author"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "BookCategory" ADD CONSTRAINT "BookCategory_bookId_fkey" FOREIGN KEY ("bookId") REFERENCES "Book"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "BookCategory" ADD CONSTRAINT "BookCategory_categoryId_fkey" FOREIGN KEY ("categoryId") REFERENCES "Category"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "Inventory" ADD CONSTRAINT "Inventory_bookId_fkey" FOREIGN KEY ("bookId") REFERENCES "Book"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "Order" ADD CONSTRAINT "Order_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "OrderItem" ADD CONSTRAINT "OrderItem_orderId_fkey" FOREIGN KEY ("orderId") REFERENCES "Order"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "OrderItem" ADD CONSTRAINT "OrderItem_bookId_fkey" FOREIGN KEY ("bookId") REFERENCES "Book"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "Review" ADD CONSTRAINT "Review_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "Review" ADD CONSTRAINT "Review_bookId_fkey" FOREIGN KEY ("bookId") REFERENCES "Book"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "WishlistItem" ADD CONSTRAINT "WishlistItem_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "WishlistItem" ADD CONSTRAINT "WishlistItem_bookId_fkey" FOREIGN KEY ("bookId") REFERENCES "Book"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "Address" ADD CONSTRAINT "Address_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "RecentlyViewed" ADD CONSTRAINT "RecentlyViewed_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "RecentlyViewed" ADD CONSTRAINT "RecentlyViewed_bookId_fkey" FOREIGN KEY ("bookId") REFERENCES "Book"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "RelatedBook" ADD CONSTRAINT "RelatedBook_bookId_fkey" FOREIGN KEY ("bookId") REFERENCES "Book"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "RelatedBook" ADD CONSTRAINT "RelatedBook_relatedBookId_fkey" FOREIGN KEY ("relatedBookId") REFERENCES "Book"("id") ON DELETE CASCADE ON UPDATE CASCADE;
